query MyQuery {
  products(first: 100) {
    edges {
      node {
        id
    description
    availableForSale
        images(first: 10) {
          edges {
            node {
              id
            }
          }
        }
        priceRange {
          maxVariantPrice {
            amount
            currencyCode
          }
          minVariantPrice {
            amount
            currencyCode
          }
        }
        title
        featuredImage {
          url
        }
        variants(first: 10) {
          edges {
            node {
              id
            }
          }
        }
      }
    }
  }
}

mutation AddToCart($cartId: ID!, $variantId: ID!, $quantity: Int!) {
  cartLinesAdd(
    cartId: $cartId
    lines: [{quantity: $quantity, merchandiseId: $variantId}]
  ) {
    cart {
      id
      checkoutUrl
      lines(first: 10) {
        edges {
          node {
            id
            quantity
            cost {
              amountPerQuantity {
                amount
                currencyCode
              }
              totalAmount {
                amount
                currencyCode
              }
              compareAtAmountPerQuantity {
                amount
                currencyCode
              }
            }
            merchandise {
              ... on ProductVariant {
                id
                title
                image {
                  url
                  altText
                }
                product {
                  id
                  title
                }
              }
            }
          }
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}

query MyQuery($handle: String!) {
  collectionByHandle(handle: $handle) {
    id
    handle
    title
    products(first: 10) {
      edges {
        node {
          id
          featuredImage {
            url
          }
          priceRange {
            minVariantPrice {
              amount
              currencyCode
            }
            maxVariantPrice {
              amount
              currencyCode
            }
          }
          compareAtPriceRange {
            maxVariantPrice {
              amount
              currencyCode
            }
            minVariantPrice {
              amount
              currencyCode
            }
          }
          variants(first: 10) {
            nodes {
              title
              id
            }
          }
          handle
          description
          availableForSale
          title
          metafield(namespace: "custom", key: "gender") {
            value
            type
            key
          }
        }
      }
    }
  }
}

mutation CreateCart($variantId: ID!, $quantity: Int!) {
  cartCreate(input: {lines: [{quantity: $quantity, merchandiseId: $variantId}]}) {
    cart {
      id
      checkoutUrl
      lines(first: 10) {
        edges {
          node {
            id
            quantity
            merchandise {
              ... on ProductVariant {
                id
                title
                image {
                  url
                  altText
                }
                product {
                  id
                  title
                }
              }
            }
            cost {
              amountPerQuantity {
                amount
                currencyCode
              }
              totalAmount {
                amount
                currencyCode
              }
              compareAtAmountPerQuantity {
                amount
                currencyCode
              }
            }
          }
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}

query GetCart($cartId: ID!) {
  cart(id: $cartId) {
    id
    checkoutUrl
    totalQuantity
    cost {
      subtotalAmount {
        amount
        currencyCode
      }
      totalAmount {
        amount
        currencyCode
      }
    }
    lines(first: 20) {
      edges {
        node {
          id
          quantity
          merchandise {
            ... on ProductVariant {
              id
              title
              price {
                amount
                currencyCode
              }
              compareAtPrice {
                amount
                currencyCode
              }
              image {
                url
                altText
              }
              product {
                title
                handle
              }
            }
          }
        }
      }
    }
    discountCodes {
      code
      applicable
    }
    discountAllocations {
      discountedAmount {
        amount
        currencyCode
      }
    }
  }
}

query ProductByHandle($handle: String!) {
  productByHandle(handle: $handle) {
  id
   title
    handle
    description
    descriptionHtml
    tags
    featuredImage {
      url
      altText
    }
    images(first: 5) {
      nodes {
        url
        altText
        id
      }
    }
     variants(first: 10) {
            nodes {
              id
              title
              availableForSale
              sku
              price {
                amount
                currencyCode
              }
              compareAtPrice {
                amount
                currencyCode
              }
              image {
                url
              }
              selectedOptions {
                name
                value
              }
            }
          }
    priceRange {
      maxVariantPrice {
        amount
        currencyCode
      }
      minVariantPrice {
        amount
        currencyCode
      }
    }
    compareAtPriceRange {
      maxVariantPrice {
        amount
        currencyCode
      }
      minVariantPrice {
        amount
        currencyCode
      }
    }
    metafields(
      identifiers: [
        {namespace: "custom", key: "product_subtitle"},
        {namespace: "custom", key: "manufacturer"},
        {namespace: "custom", key: "reasons_to_love_image"},
        {namespace: "custom", key: "reasons_to_love_object"},
        {namespace: "custom", key: "product_details"},
        {namespace: "custom", key: "disclaimer"},
        {namespace: "custom", key: "product_faq"},
        {namespace: "custom", key: "trust_badges"},
        {namespace: "reviews", key: "rating"},
        {namespace: "reviews", key: "rating_count"},
        {namespace: "custom", key: "dimensions"},
        {namespace: "custom", key: "license_number"},
        {namespace: "custom", key: "best_before"},
        {namespace: "custom", key: "generic_name"},
        {namespace: "custom", key: "variants"}
      ]
    ) {
      key
      namespace
      value
      type
      references(first: 10) {
        nodes {
          ... on Metaobject {
            id
            type
            fields {
              key
              value
              type
              reference {
                ... on Product {
                  id
                  title
                  handle
                  featuredImage {
                    url
                    altText
                  }
                  priceRange {
                    maxVariantPrice {
                      amount
                    }
                  }
                }
                ... on MediaImage {
                  id
                  image {
                    url
                    altText
                  }
                }
                ... on GenericFile {
                  id
                  url
                  mimeType
                }
                ... on Metaobject {
                  id
                  type
                  fields {
                    key
                    value
                    type
                    reference {
                      ... on MediaImage {
                        id
                        image {
                          url
                          altText
                        }
                      }
                    }
                  }
                }
              }
              references(first: 10) {
                nodes {
                  ... on Metaobject {
                    id
                    type
                    fields {
                      key
                      value
                      type
                      reference {
                        ... on MediaImage {
                          id
                          image {
                            url
                            altText
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
      reference {
        ... on MediaImage {
          id
          image {
            url
            altText
          }
        }
      }
    }
  }
}

mutation UpdateCart($cartId: ID!, $lines: [CartLineUpdateInput!]!) {
  cartLinesUpdate(cartId: $cartId, lines: $lines) {
    cart {
      id
      lines(first: 10) {
        edges {
          node {
            id
            quantity
            cost {
              totalAmount {
                amount
                currencyCode
              }
            }
            merchandise {
              ... on ProductVariant {
                id
                title
                image {
                  url
                  altText
                }
                product {
                  id
                  title
                }
              }
            }
          }
        }
      }
    }
    userErrors {
      field
      message
    }
  }
}
